testKeyExpansionAES128 ∷ PropertyT IO ()
testKeyExpansionAES128 = keyExpansion (Proxy @(Spec.AES128 ∷ Spec.AES)) key1AES128 === w1AES128

testCipherAES128 ∷ PropertyT IO ()
testCipherAES128 = cipher  (Proxy @(Spec.AES128 ∷ Spec.AES)) in1AES128 (keyExpansion  (Proxy @(Spec.AES128 ∷ Spec.AES)) key1AES128) === out1AES128

testInvCipherAES128 ∷ PropertyT IO ()
testInvCipherAES128 = invCipher (Proxy @(Spec.AES128 ∷ Spec.AES))  out1AES128  w1AES128 === in1AES128


